SELECT COUNT(project_id) AS TotalProjects
FROM procurement_projects
WHERE status = 'Open' AND procurement_mode = 'Sealed Bid' AND source_of_funds LIKE '%Fund%';

SELECT project_id, year, description, total_amount
FROM procurement_projects
ORDER BY total_amount DESC;

SELECT pp.project_id, pp.description AS project_name, pm.mode_name AS procurement_mode
FROM procurement_projects pp
INNER JOIN procurement_modes pm ON pp.procurement_mode = pm.mode_id;

SELECT year, MIN(total_amount) AS min_total_amount, MAX(total_amount) AS max_total_amount 
FROM procurement_projects 
GROUP BY year;

SELECT *
FROM procurement_projects
ORDER BY total_amount DESC;

SELECT * 
FROM procurement_projects 
WHERE project_id = 123;

SELECT pp.project_id, al.user_id, al.action
FROM procurement_projects pp
JOIN audit_logs al ON pp.project_id = al.project_id;

SELECT pp.*, al.*
FROM procurement_projects pp
JOIN audit_logs al ON pp.project_id = al.project_id;

SELECT MIN(total_amount) 
FROM procurement_projects 
WHERE year = 2019;
